+using System.Linq.Expressions;
+
+namespace Data.Repositories;
+
+public interface IUserRepository
+{
+    Task<User> GetByIdAsync(int id);
+    Task<IEnumerable<User>> GetAllAsync();
+    Task<User> AddAsync(User user);
+    Task UpdateAsync(User user);
+    Task DeleteAsync(int id);
+    Task<IEnumerable<User>> FindAsync(Expression<Func<User, bool>> predicate);
+}
+
+public class UserRepository : IUserRepository
+{
+    private readonly AppDbContext _context;
+    private readonly ILogger<UserRepository> _logger;
+
+    public UserRepository(AppDbContext context, ILogger<UserRepository> logger)
+    {
+        _context = context;
+        _logger = logger;
+    }
+
+    public async Task<User> GetByIdAsync(int id)
+    {
+        _logger.LogDebug("Getting user by ID: {UserId}", id);
+        return await _context.Users
+            .Include(u => u.Profile)
+            .FirstOrDefaultAsync(u => u.Id == id);
+    }
+
+    public async Task<IEnumerable<User>> GetAllAsync()
+    {
+        return await _context.Users.ToListAsync();
+    }
+
+    public async Task<User> AddAsync(User user)
+    {
+        _context.Users.Add(user);
+        await _context.SaveChangesAsync();
+        _logger.LogInformation("Added new user with ID: {UserId}", user.Id);
+        return user;
+    }
+
+    public async Task UpdateAsync(User user)
+    {
+        _context.Entry(user).State = EntityState.Modified;
+        await _context.SaveChangesAsync();
+        _logger.LogInformation("Updated user with ID: {UserId}", user.Id);
+    }
+
+    public async Task DeleteAsync(int id)
+    {
+        var user = await GetByIdAsync(id);
+        if (user != null)
+        {
+            _context.Users.Remove(user);
+            await _context.SaveChangesAsync();
+            _logger.LogInformation("Deleted user with ID: {UserId}", id);
+        }
+    }
+
+    public async Task<IEnumerable<User>> FindAsync(Expression<Func<User, bool>> predicate)
+    {
+        return await _context.Users.Where(predicate).ToListAsync();
+    }
+}
